     */
    private static class TypeCodecRemovalListener implements RemovalListener<CacheKey, TypeCodec<?>>
    {
        @Override
        public void onRemoval(RemovalNotification<CacheKey, TypeCodec<?>> notification)
        {
            logger.trace(
